-- AptiPath v3 DB-driven career catalog and adjustments
-- Generated by tools/generate-aptipath-career-dataset.ps1

DROP TABLE IF EXISTS rd_ci_career_adjustment;
DROP TABLE IF EXISTS rd_ci_career_catalog;

CREATE TABLE IF NOT EXISTS rd_ci_career_catalog (
  ci_career_catalog_id BIGINT NOT NULL AUTO_INCREMENT,
  module_code VARCHAR(40) NOT NULL,
  assessment_version VARCHAR(20) NOT NULL,
  career_code VARCHAR(80) NOT NULL,
  career_name VARCHAR(190) NOT NULL,
  cluster_name VARCHAR(190) NOT NULL,
  fit_strategy VARCHAR(40) DEFAULT NULL,
  pathway_hint VARCHAR(500) DEFAULT NULL,
  exam_hint VARCHAR(500) DEFAULT NULL,
  prerequisite_summary VARCHAR(600) DEFAULT NULL,
  required_subjects_csv VARCHAR(255) DEFAULT NULL,
  entrance_exams_csv VARCHAR(255) DEFAULT NULL,
  min_math_level TINYINT DEFAULT NULL,
  min_physics_level TINYINT DEFAULT NULL,
  min_chemistry_level TINYINT DEFAULT NULL,
  min_biology_level TINYINT DEFAULT NULL,
  min_language_level TINYINT DEFAULT NULL,
  target_phase VARCHAR(40) DEFAULT NULL,
  sort_order INT NOT NULL DEFAULT 0,
  status VARCHAR(20) NOT NULL DEFAULT 'ACTIVE',
  created_at DATETIME NOT NULL,
  updated_at DATETIME NOT NULL,
  PRIMARY KEY (ci_career_catalog_id),
  UNIQUE KEY uq_rd_ci_career_catalog_code (module_code, assessment_version, career_code),
  KEY idx_rd_ci_career_catalog_cluster (module_code, assessment_version, cluster_name, status)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

CREATE TABLE IF NOT EXISTS rd_ci_career_adjustment (
  ci_career_adjustment_id BIGINT NOT NULL AUTO_INCREMENT,
  module_code VARCHAR(40) NOT NULL,
  assessment_version VARCHAR(20) NOT NULL,
  signal_type VARCHAR(40) NOT NULL,
  signal_code VARCHAR(80) NOT NULL,
  signal_band VARCHAR(20) NOT NULL DEFAULT 'ANY',
  cluster_name VARCHAR(190) NOT NULL,
  boost_value DECIMAL(6,2) NOT NULL,
  sort_order INT NOT NULL DEFAULT 0,
  status VARCHAR(20) NOT NULL DEFAULT 'ACTIVE',
  created_at DATETIME NOT NULL,
  updated_at DATETIME NOT NULL,
  PRIMARY KEY (ci_career_adjustment_id),
  UNIQUE KEY uq_rd_ci_career_adjustment (module_code, assessment_version, signal_type, signal_code, signal_band, cluster_name),
  KEY idx_rd_ci_career_adjustment_lookup (module_code, assessment_version, signal_type, signal_code, signal_band, status)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;

DELETE FROM rd_ci_career_adjustment WHERE module_code = 'APTIPATH' AND assessment_version = 'v3';
DELETE FROM rd_ci_career_catalog WHERE module_code = 'APTIPATH' AND assessment_version = 'v3';



